+
+import { randomUUID } from 'crypto';
+
+/**
+ * Pattern type
+ */
+export type PatternType = 'task-routing' | 'error-recovery' | 'optimization' | 'learning';
+
+/**
+ * Pattern properties
+ */
+export interface PatternProps {
+  id?: string;
+  type: PatternType;
+  name: string;
