+  private static readonly DANGEROUS_COMMANDS = [
+    /^rm\s+-rf\s+\//,
+    /^rm\s+-rf\s+\*/,
+    /^dd\s+if=/,
+    /^mkfs\./,
+    /^format\s+/i,
+    /^del\s+\/s\s+\/q/i,
+    />\s*\/dev\/sd[a-z]/,
+    /\|\s*bash$/,
+    /\|\s*sh$/,
+    /eval\s*\(/,
+    /exec\s*\(/,
+  ];
+
+  // SQL injection patterns
+  private static readonly SQL_INJECTION_PATTERNS = [
+    /'\s*OR\s+'1'\s*=\s*'1/i,
+    /'\s*OR\s+1\s*=\s*1/i,
+    /;\s*DROP\s+TABLE/i,
+    /;\s*DELETE\s+FROM/i,
+    /UNION\s+SELECT/i,
+    /--\s*$/,
+  ];
